/**
 * @suppress
 */
public object FfiConverterTypeConnectionPublicState : FfiConverterRustBuffer<ConnectionPublicState>{
    override fun read(buf: ByteBuffer): ConnectionPublicState {
        return when(buf.getInt()) {
            1 -> ConnectionPublicState.Disconnected(
                FfiConverterOptionalString.read(buf),
                FfiConverterOptionalTypeConnectionIssueHint.read(buf),
                )
            2 -> ConnectionPublicState.Connecting
            3 -> ConnectionPublicState.Connected(
                FfiConverterString.read(buf),
                )
            4 -> ConnectionPublicState.Error(
                FfiConverterString.read(buf),
                )
            5 -> ConnectionPublicState.Reconnecting(
                FfiConverterUInt.read(buf),
                FfiConverterUInt.read(buf),
                FfiConverterOptionalString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ConnectionPublicState) = when(value) {
        is ConnectionPublicState.Disconnected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterOptionalString.allocationSize(value.`reason`)
                + FfiConverterOptionalTypeConnectionIssueHint.allocationSize(value.`issueHint`)
            )
        }
        is ConnectionPublicState.Connecting -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is ConnectionPublicState.Connected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`host`)
            )
        }
        is ConnectionPublicState.Error -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
        is ConnectionPublicState.Reconnecting -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`elapsedSecs`)
                + FfiConverterUInt.allocationSize(value.`timeoutSecs`)
                + FfiConverterOptionalString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: ConnectionPublicState, buf: ByteBuffer) {
        when(value) {
            is ConnectionPublicState.Disconnected -> {
                buf.putInt(1)
                FfiConverterOptionalString.write(value.`reason`, buf)
                FfiConverterOptionalTypeConnectionIssueHint.write(value.`issueHint`, buf)
                Unit
            }
            is ConnectionPublicState.Connecting -> {
                buf.putInt(2)
                Unit
            }
            is ConnectionPublicState.Connected -> {
                buf.putInt(3)
                FfiConverterString.write(value.`host`, buf)
                Unit
            }
            is ConnectionPublicState.Error -> {
                buf.putInt(4)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is ConnectionPublicState.Reconnecting -> {
                buf.putInt(5)
                FfiConverterUInt.write(value.`elapsedSecs`, buf)
                FfiConverterUInt.write(value.`timeoutSecs`, buf)
                FfiConverterOptionalString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





